export function getSyllabusForSubject(subjectId, subjectName) {
  if (syllabusCatalog[subjectId]) {
    return syllabusCatalog[subjectId];
  }
  // Dynamic fallback syllabus checklist generator
  return {
    code: 'CORE-SUB',
    credits: 3.5,
    description: `Syllabus and topics overview for ${subjectName}.`,
    units: [
      { id: `${subjectId}-u1`, name: 'Unit 1: Introduction & Basic Concepts', topics: ['Foundational concepts', 'Overview of scope and objectives', 'Terminology and definitions'] },
      { id: `${subjectId}-u2`, name: 'Unit 2: Core Methodologies', topics: ['Key processes and steps', 'Methods of analysis and development', 'Intermediate systems and applications'] },
      { id: `${subjectId}-u3`, name: 'Unit 3: Advanced Applications', topics: ['Complex scenarios and extensions', 'Real-world case studies', 'System optimization and scaling'] },
      { id: `${subjectId}-u4`, name: 'Unit 4: Future Trends & Review', topics: ['Emerging topics and techniques', 'Practical evaluation and review', 'Synthesis of concepts'] }
    ]
  };
}
